import React, { createContext, useState, useContext } from 'react';

// 1. Tạo Context
export const DataContext = createContext();

// 2. Tạo Hook useData để các file cũ (StaffLayout) có thể dùng được
export const useData = () => {
    return useContext(DataContext);
};

export const DataProvider = ({ children }) => {
  // --- MOCK DATA ---
  
  const [staffList, setStaffList] = useState([
    { 
      id: 1, name: 'Nguyễn Văn A', role: 'Staff', 
      ubi1_percent: 50, ubi2_percent: 30, remuneration: 5000000 
    },
    { 
      id: 2, name: 'Trần Thị B', role: 'Staff',
      ubi1_percent: 60, ubi2_percent: 20, remuneration: 6000000 
    },
  ]);

  const [disciplineTypes, setDisciplineTypes] = useState([
    { id: 1, name: 'Trừ 10% lương', status: 'Approved', createdBy: 'Regulatory Admin' },
    { id: 2, name: 'Cảnh cáo toàn công ty', status: 'Pending', createdBy: 'Operational Admin' },
  ]);

  const [disciplineRecords, setDisciplineRecords] = useState([
    { id: 1, staffId: 1, violation: 'Đi trễ 3 ngày', disciplineId: 1, date: '2023-10-20T08:00', status: 'Active' }
  ]);

  const [tasks, setTasks] = useState([
    { 
      id: 1, title: 'Thiết kế Banner', assigneeId: 1, 
      startTime: '2023-10-25T08:00', deadline: '2023-10-27T17:00', 
      jobRole: 'ST', incomeType: 'UBI 1', disciplineId: 1,
      progress: 80, status: 'In Progress', explanation: '',
      isUrgent: true 
    },
    { 
      id: 2, title: 'Báo cáo tuần', assigneeId: 1, 
      startTime: '2023-10-20T08:00', deadline: '2023-10-21T17:00', 
      jobRole: 'CCA', incomeType: 'Remuneration', disciplineId: 1,
      progress: 50, status: 'Overdue', explanation: '',
      isUrgent: false
    }
  ]);

  const [facilityReports, setFacilityReports] = useState([]);

  // --- ACTIONS ---

  const addStaff = (newStaff) => setStaffList([...staffList, { ...newStaff, id: Date.now() }]);
  
  const addTask = (newTask) => setTasks([...tasks, { ...newTask, id: Date.now(), progress: 0, status: 'New' }]);
  
  const updateTask = (taskId, updates) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, ...updates } : t));
  };

  const addDisciplineType = (item) => setDisciplineTypes([...disciplineTypes, { ...item, id: Date.now() }]);
  
  const updateDisciplineTypeStatus = (id, status) => {
    setDisciplineTypes(disciplineTypes.map(d => d.id === id ? { ...d, status } : d));
  };

  const addDisciplineRecord = (record) => setDisciplineRecords([...disciplineRecords, { ...record, id: Date.now(), status: 'Active' }]);

  const requestDeleteDisciplineRecord = (id) => {
    setDisciplineRecords(disciplineRecords.map(r => r.id === id ? { ...r, status: 'Pending_Deletion' } : r));
  };

  const approveDeleteDisciplineRecord = (id) => {
    setDisciplineRecords(disciplineRecords.filter(r => r.id !== id));
  };

  const submitFacilityReport = (report) => {
    setFacilityReports([...facilityReports, { ...report, id: Date.now(), timestamp: new Date().toISOString() }]);
  };

  return (
    <DataContext.Provider value={{
      staffList, addStaff,
      tasks, addTask, updateTask,
      disciplineTypes, addDisciplineType, updateDisciplineTypeStatus,
      disciplineRecords, addDisciplineRecord, requestDeleteDisciplineRecord, approveDeleteDisciplineRecord,
      facilityReports, submitFacilityReport
    }}>
      {children}
    </DataContext.Provider>
  );
};
